import{_ as a,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"electrobun","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/electrobun-开发工具.md","filePath":"github汇总/开发工具/electrobun-开发工具.md"}'),n={name:"github汇总/开发工具/electrobun-开发工具.md"};function o(t,l,h,c,d,s){return e(),i("div",null,l[0]||(l[0]=[r('<h1 id="electrobun" tabindex="-1">electrobun <a class="header-anchor" href="#electrobun" aria-label="Permalink to “electrobun”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>electrobun</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>blackboardsh</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>开发工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>传统桌面应用开发需要学习多种语言、打包体积大、更新麻烦。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>使用TypeScript构建超快、超小、跨平台桌面应用的完整解决方案。使用Bun作为主进程执行引擎，用Zig编写原生绑定。打包体积约12MB，更新包可小至14KB。提供主进程和Webview进程之间的隔离，支持快速、类型安全的RPC通信。支持macOS、Windows和Linux三大平台。提供模板和完整的开发工作流。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>打包体积约12MB，更新包可小至14KB</li><li>使用Bun执行引擎和Zig原生绑定</li><li>主进程和Webview进程隔离</li><li>快速、类型安全的RPC通信</li><li>支持macOS、Windows、Linux</li><li>5分钟开始写代码，10分钟发布应用</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/blackboardsh/electrobun" target="_blank" rel="noreferrer">https://github.com/blackboardsh/electrobun</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用Electrobun开发桌面应用的开发者。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Node.js版本</strong></p><ul><li>执行命令：<code>node -v</code></li><li>通过标准：显示Node.js版本号</li></ul></li><li><p><strong>检查Bun是否安装</strong></p><ul><li>执行命令：<code>bun -v</code></li><li>通过标准：显示Bun版本号</li></ul></li></ol><h3 id="主路径-使用模板快速开始" tabindex="-1">主路径：使用模板快速开始 <a class="header-anchor" href="#主路径-使用模板快速开始" aria-label="Permalink to “主路径：使用模板快速开始”">​</a></h3><p><strong>步骤1：初始化项目</strong></p><ul><li>目标：使用模板创建新项目</li><li>位置：终端</li><li>命令：<code>npx electrobun init</code></li><li>成功标志：项目创建成功</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：进入项目目录</strong></p><ul><li>目标：进入项目文件夹</li><li>位置：终端</li><li>命令：<code>cd &lt;项目名称&gt;</code></li><li>成功标志：进入项目目录</li><li>失败处理：确认项目名称正确</li></ul><p><strong>步骤3：安装依赖</strong></p><ul><li>目标：安装项目依赖</li><li>位置：项目目录</li><li>命令：<code>bun install</code></li><li>成功标志：依赖安装完成</li><li>失败处理：检查Bun是否正确安装</li></ul><p><strong>步骤4：运行开发模式</strong></p><ul><li>目标：启动开发服务器</li><li>位置：项目目录</li><li>命令：<code>bun dev</code></li><li>成功标志：应用启动成功</li><li>失败处理：检查端口是否被占用</li></ul><h3 id="备选路径-从源码构建" tabindex="-1">备选路径：从源码构建 <a class="header-anchor" href="#备选路径-从源码构建" aria-label="Permalink to “备选路径：从源码构建”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取源码</li><li>位置：终端</li><li>命令：<code>git clone --recurse-submodules https://github.com/blackboardsh/electrobun.git</code></li><li>成功标志：项目克隆成功</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：安装依赖</strong></p><ul><li>目标：安装项目依赖</li><li>位置：项目目录</li><li>命令：<code>cd electrobun/package &amp;&amp; bun install</code></li><li>成功标志：依赖安装完成</li><li>失败处理：检查Bun版本</li></ul><p><strong>步骤3：运行开发环境</strong></p><ul><li>目标：启动开发环境</li><li>位置：项目目录</li><li>命令：<code>bun dev:clean</code></li><li>成功标志：开发环境启动成功</li><li>失败处理：检查系统依赖</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>应用窗口正常打开</li><li>可以看到Electrobun默认界面</li><li>热重载功能正常工作</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>Bun命令不存在</strong></p><ul><li>可能原因：Bun未安装</li><li>解决步骤：运行 <code>curl -fsSL https://bun.sh/install | bash</code> 安装Bun</li></ul></li><li><p><strong>应用无法启动</strong></p><ul><li>可能原因：系统依赖缺失</li><li>解决步骤：安装对应平台的开发工具（macOS需要Xcode命令行工具）</li></ul></li><li><p><strong>打包失败</strong></p><ul><li>可能原因：缺少平台特定工具</li><li>解决步骤：安装对应平台的构建工具</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://blackboard.sh/electrobun/" target="_blank" rel="noreferrer">Electrobun Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',44)]))}const p=a(n,[["render",o]]);export{b as __pageData,p as default};
